arguments.argument:
if global.gamePaused=false
{
  with oPlayer1
  {
    if isCollisionWaterBottom(-12)
    {
      if global.desertHeat<1500 {global.desertHeat+=60}
      else {global.desertHeat=1500}
    }
    else
    {
      global.desertHeat-=1
      if global.desertHeat<=0
      {
        oPlayer1.life-=oPlayer1.maxLife
      }
    }
  }
}
